token = _get_access_token(TENANT_ID, CLIENT_ID, CLIENT_SECRET)
headers = {
    'Authorization': f'Bearer {token}',
    'Content-Type': 'application/json',
}
print('Token acquired.')

def create_classification_type(name: str, description: str) -> dict:
    payload = {
        'classificationDefs': [
            {
                'name': name,
                'description': description,
                'superTypes': [],
                'attributeDefs': [],
            }
        ]
    }
    url = f'{ATLAS_BASE}/types/typedefs'
    resp = requests.post(url, headers=headers, json=payload, timeout=60)
    if resp.status_code == 409 or (resp.ok and 'classificationDefs' in resp.json()):
        return resp.json()
    resp.raise_for_status()
    return resp.json()


result = create_classification_type(
    CLASSIFICATION_NAME,
    'UK postcode — anonymised to the first outward block (e.g. SW1W 9SP becomes SW1W).',
)
defs = result.get('classificationDefs', [])
if defs:
    print(f'Classification type created/confirmed: {defs[0]["name"]}')
else:
    print(f'Response: {result}')

def get_rule_version(rule_name: str) -> int:
    """Return the current version of an existing rule, or 0 if it does not exist."""
    url = f'{SCAN_BASE}/classificationrules/{rule_name}?api-version={SCAN_API_VERSION}'
    resp = requests.get(url, headers=headers, timeout=60)
    if resp.status_code == 404:
        return 0
    if not resp.ok:
        raise RuntimeError(f'GET {url} -> {resp.status_code}: {resp.text[:800]}')
    return resp.json().get('properties', {}).get('version', 0)


def upsert_classification_rule(rule_name: str, classification_name: str, regex: str) -> dict:
    current_version = get_rule_version(rule_name)
    print(f'Current rule version: {current_version} — will write version {current_version + 1}')
    payload = {
        'kind': 'Custom',
        'properties': {
            'classificationName': classification_name,
            'ruleStatus': 'Enabled',
            'minimumPercentageMatch': 60,
            'version': current_version + 1,
            'dataPatterns': [
                {
                    'kind': 'Regex',
                    'pattern': regex,
                }
            ],
            'columnPatterns': [
                {
                    'kind': 'Regex',
                    'pattern': '(?i)(^|_)(post_?code|postal_?code)(_|$)',
                }
            ],
        },
    }
    url = f'{SCAN_BASE}/classificationrules/{rule_name}?api-version={SCAN_API_VERSION}'
    resp = requests.put(url, headers=headers, json=payload, timeout=60)
    if not resp.ok:
        raise RuntimeError(f'PUT {url} -> {resp.status_code}: {resp.text[:800]}')
    return resp.json()


result = upsert_classification_rule(RULE_NAME, CLASSIFICATION_NAME, UK_POSTCODE_REGEX)
print(f'Classification rule upserted: {result.get("name", RULE_NAME)}')
print(f'Status: {result.get("properties", {}).get("ruleStatus")}')
print(f'Version: {result.get("properties", {}).get("version")}')
